import{_ as o,c as t,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"隐私安全: 脱敏与密钥 | opencode-supermemory","description":"学习 opencode-supermemory 的隐私保护机制。掌握 private 标签脱敏数据、安全配置 API Key 以及理解数据流向，保护敏感信息不泄露。","frontmatter":{"title":"隐私安全: 脱敏与密钥 | opencode-supermemory","sidebarTitle":"保护你的敏感信息","subtitle":"隐私安全: 脱敏与密钥 | opencode-supermemory","description":"学习 opencode-supermemory 的隐私保护机制。掌握 private 标签脱敏数据、安全配置 API Key 以及理解数据流向，保护敏感信息不泄露。","tags":["隐私","安全","配置"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"zh/supermemoryai/opencode-supermemory/security/privacy/index.md","filePath":"zh/supermemoryai/opencode-supermemory/security/privacy/index.md"}'),s={name:"zh/supermemoryai/opencode-supermemory/security/privacy/index.md"};function i(n,e,d,c,l,p){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="隐私与数据安全-如何保护你的敏感信息" tabindex="-1">隐私与数据安全：如何保护你的敏感信息 <a class="header-anchor" href="#隐私与数据安全-如何保护你的敏感信息" aria-label="Permalink to &quot;隐私与数据安全：如何保护你的敏感信息&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li><strong>理解数据去哪了</strong>：清楚知道哪些数据会上传到云端，哪些会留在本地。</li><li><strong>掌握脱敏技巧</strong>：学会使用 <code>&lt;private&gt;</code> 标签防止敏感信息（如密码、密钥）被上传。</li><li><strong>安全管理密钥</strong>：学会以最安全的方式配置 <code>SUPERMEMORY_API_KEY</code>。</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>在使用 opencode-supermemory 时，理解数据流向至关重要：</p><ol><li><strong>云端存储</strong>：你的记忆（Memories）是存储在 Supermemory 的云端数据库中的，而不是本地文件。这意味着你需要网络连接才能存取记忆。</li><li><strong>本地脱敏</strong>：为了保护隐私，插件在将数据发送到云端<strong>之前</strong>，会在本地进行脱敏处理。</li><li><strong>显式控制</strong>：插件不会自动扫描所有文件上传，只有 Agent 显式调用 <code>add</code> 工具或触发压缩时，相关内容才会被处理。</li></ol><h3 id="脱敏机制" tabindex="-1">脱敏机制 <a class="header-anchor" href="#脱敏机制" aria-label="Permalink to &quot;脱敏机制&quot;">​</a></h3><p>插件内置了一个简单的过滤器，专门识别 <code>&lt;private&gt;</code> 标签。</p><ul><li><strong>输入</strong>：<code>这里的数据库密码是 &lt;private&gt;123456&lt;/private&gt;</code></li><li><strong>处理</strong>：插件检测到标签，将其内容替换为 <code>[REDACTED]</code>。</li><li><strong>上传</strong>：<code>这里的数据库密码是 [REDACTED]</code></li></ul><div class="info custom-block"><p class="custom-block-title">提示</p><p>这个处理过程发生在插件内部代码中，在数据离开你的电脑之前就已经完成了。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-安全配置-api-key" tabindex="-1">第 1 步：安全配置 API Key <a class="header-anchor" href="#第-1-步-安全配置-api-key" aria-label="Permalink to &quot;第 1 步：安全配置 API Key&quot;">​</a></h3><p>虽然你可以将 API Key 直接写入配置文件，但为了防止意外泄露（比如误把配置文件分享给别人），我们推荐了解优先级的逻辑。</p><p><strong>优先级规则</strong>：</p><ol><li><strong>配置文件</strong> (<code>~/.config/opencode/supermemory.jsonc</code>)：优先级最高。</li><li><strong>环境变量</strong> (<code>SUPERMEMORY_API_KEY</code>)：如果配置文件中未设置，则使用此变量。</li></ol><p><strong>推荐做法</strong>： 如果你希望灵活切换或在 CI/CD 环境中使用，请使用环境变量。如果你是个人开发者，配置在用户目录的 JSONC 文件中也是安全的（因为它不在你的项目 Git 仓库里）。</p><h3 id="第-2-步-使用-private-标签" tabindex="-1">第 2 步：使用 <code>&lt;private&gt;</code> 标签 <a class="header-anchor" href="#第-2-步-使用-private-标签" aria-label="Permalink to &quot;第 2 步：使用 `&lt;private&gt;` 标签&quot;">​</a></h3><p>当你在对话中通过自然语言让 Agent 记住某些包含敏感信息的内容时，可以使用 <code>&lt;private&gt;</code> 标签包裹敏感部分。</p><p><strong>操作演示</strong>：</p><p>告诉 Agent：</p><blockquote><p>请记住，生产环境的数据库 IP 是 192.168.1.10，但 root 密码是 <code>&lt;private&gt;SuperSecretPwd!&lt;/private&gt;</code>，不要泄露密码。</p></blockquote><p><strong>你应该看到</strong>： Agent 会调用 <code>supermemory</code> 工具保存记忆。虽然 Agent 的回复可能包含密码（因为它在上下文中），但<strong>实际保存到 Supermemory 云端的记忆</strong>已经被脱敏。</p><h3 id="第-3-步-验证脱敏结果" tabindex="-1">第 3 步：验证脱敏结果 <a class="header-anchor" href="#第-3-步-验证脱敏结果" aria-label="Permalink to &quot;第 3 步：验证脱敏结果&quot;">​</a></h3><p>我们可以通过搜索来验证刚才的密码是否真的没被存进去。</p><p><strong>操作</strong>： 让 Agent 搜索刚才的记忆：</p><blockquote><p>搜索一下生产环境数据库的密码。</p></blockquote><p><strong>预期结果</strong>： Agent 从 Supermemory 检索到的内容应该是： <code>生产环境的数据库 IP 是 192.168.1.10，但 root 密码是 [REDACTED]...</code></p><p>如果 Agent 告诉你&quot;密码是 [REDACTED]&quot;，说明脱敏机制工作正常。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">误区 1：所有代码都会被上传</p><p><strong>事实</strong>：插件<strong>不会</strong>自动上传你的整个代码库。它只有在执行 <code>/supermemory-init</code> 进行初始化扫描，或者 Agent 显式决定&quot;记住&quot;某段代码逻辑时，才会将那特定的片段上传。</p></div><div class="warning custom-block"><p class="custom-block-title">误区 2：.env 文件会自动加载</p><p><strong>事实</strong>：插件读取的是进程环境中的 <code>SUPERMEMORY_API_KEY</code>。如果你在项目根目录放了一个 <code>.env</code> 文件，插件<strong>不会</strong>自动读取它，除非你使用的终端或 OpenCode 主程序加载了它。</p></div><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>隐私脱敏逻辑</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/privacy.ts#L1-L13" target="_blank" rel="noreferrer"><code>src/services/privacy.ts</code></a></td><td>1-13</td></tr><tr><td>API Key 加载</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L90" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>90</td></tr><tr><td>插件调用脱敏</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L282" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>282</td></tr></tbody></table><p><strong>关键函数</strong>：</p><ul><li><code>stripPrivateContent(content)</code>: 执行正则替换，将 <code>&lt;private&gt;</code> 内容变为 <code>[REDACTED]</code>。</li><li><code>loadConfig()</code>: 加载本地配置文件，优先级高于环境变量。</li></ul></details><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>恭喜你完成了 opencode-supermemory 的核心课程！</p><p>接下来你可以：</p><ul><li>回顾 <a href="/docs/opencodedocs/zh/supermemoryai/opencode-supermemory/advanced/configuration/">高级配置</a> 了解更多自定义选项。</li></ul></blockquote>',35)])])}const g=o(s,[["render",i]]);export{m as __pageData,g as default};
